import{_ as a,c as e}from"./app.56afa649.js";const r={},t=e('<h1 id="foretag" tabindex="-1"><a class="header-anchor" href="#foretag" aria-hidden="true">#</a> F\xF6retag</h1><h2 id="var-version-foretag" tabindex="-1"><a class="header-anchor" href="#var-version-foretag" aria-hidden="true">#</a> V\xE5r version (f\xF6retag)</h2><p>Vi gillar att g\xF6ra saker annorlunda och d\xE4rf\xF6r har vi skapat f\xF6retag p\xE5 Ekstammen. Ist\xE4llet f\xF6r att man som oftast f\xE5r pengar f\xF6r att utf\xF6ra ett arbete som t.ex. mina ett block eller hugga ner ett tr\xE4d s\xE5 f\xE5r du pengar varje kvart. Dessa pengar som du f\xE5r varje kvart kallar vi f\xF6r l\xF6n.</p><h2 id="loner" tabindex="-1"><a class="header-anchor" href="#loner" aria-hidden="true">#</a> L\xF6ner</h2><p>N\xE4r du har b\xF6rjat arbeta p\xE5 ett f\xF6retag s\xE5 kommer du f\xE5 l\xF6n d\xE4rifr\xE5n. F\xF6r att \xF6ka din l\xF6n m\xE5ste du arbete med dom sysslorna som ditt f\xF6retag sysslar med. Varje kvart kommer du f\xE5r l\xF6n vilket du kommer se i ett meddelande h\xF6gst upp p\xE5 sk\xE4rmen.</p><h2 id="arbetslos" tabindex="-1"><a class="header-anchor" href="#arbetslos" aria-hidden="true">#</a> Arbetsl\xF6s</h2><p>Om du inte arbetar f\xF6r n\xE5got f\xF6retag s\xE5 kommer du f\xE5 en liten summa pengar fr\xE5n Ekstammen. Ingen g\xE5r helt utan pengar. Summan som du f\xE5r som arbetsl\xF6s kommer aldrig att \xF6ka.</p><h2 id="borja-arbeta" tabindex="-1"><a class="header-anchor" href="#borja-arbeta" aria-hidden="true">#</a> B\xF6rja arbeta</h2><p>F\xF6r att b\xF6rja arbeta ett f\xF6retag m\xE5ste du f\xF6rst prata med chefen p\xE5 det f\xF6retaget du vill b\xF6rja arbeta hos. Alla chefer hittar du i spawn eller om du skriver /warp f\xF6retag.</p><h2 id="vara-foretag-chefer" tabindex="-1"><a class="header-anchor" href="#vara-foretag-chefer" aria-hidden="true">#</a> V\xE5ra f\xF6retag &amp; Chefer</h2><h3 id="bosses-stenbrott-chef-bosse" tabindex="-1"><a class="header-anchor" href="#bosses-stenbrott-chef-bosse" aria-hidden="true">#</a> Bosses stenbrott (Chef Bosse)</h3><p>Om det \xE4r mining du vill syssla med s\xE5 \xE4r Bosses stenbrott f\xF6retaget F\xF6r dig. Bosse betalar pengar till alla miners d\xE4r ute.</p><h3 id="wilmas-bonder-chef-wilma" tabindex="-1"><a class="header-anchor" href="#wilmas-bonder-chef-wilma" aria-hidden="true">#</a> Wilmas b\xF6nder (Chef Wilma)</h3><p>Om du tycker det \xE4r roligt att plantera gr\xF6nska, hugga tr\xE4d, ta hand om djur s\xE5 \xE4r det Wilmas b\xF6nder du ska arbeta f\xF6r. Hon betalar n\xE4mligen ut pengar till alla b\xF6nder p\xE5 servern.</p><h3 id="bullens-bygg-chef-bullen" tabindex="-1"><a class="header-anchor" href="#bullens-bygg-chef-bullen" aria-hidden="true">#</a> Bullens bygg (Chef bullen)</h3><p>\xC4r bygga sin stora passion i minecraft? D\xE5 \xE4r det Bullens bygg du sak v\xE4nda dig till. Bullen st\xE5r f\xF6r alla byggares l\xF6ner.</p><h3 id="kents-jaktstuga-chef-kent" tabindex="-1"><a class="header-anchor" href="#kents-jaktstuga-chef-kent" aria-hidden="true">#</a> Kents jaktstuga (Chef Kent)</h3><p>\xC4r du som Kent och gillar att fiska, jaga, enchanta och brygga magiska drycker? D\xE5 \xE4r Kents jaktstuga det sj\xE4lvklara valet f\xF6r dig. Han st\xE5r f\xF6r alla j\xE4gares l\xF6ner.</p><h2 id="uppsagning-byta-foretag" tabindex="-1"><a class="header-anchor" href="#uppsagning-byta-foretag" aria-hidden="true">#</a> Upps\xE4gning/byta f\xF6retag</h2><p>Om du vill byta f\xF6retag och syssla med n\xE5got annat s\xE5 kan du prata med n\xE5gon av v\xE5ra arbetsgivare s\xE5 guidar dig dig till hur du s\xE4ger upp dig.</p><h2 id="snabb-guide-borja-arbeta" tabindex="-1"><a class="header-anchor" href="#snabb-guide-borja-arbeta" aria-hidden="true">#</a> Snabb guide &quot;B\xF6rja arbeta&quot;</h2><ol><li>Prata med en Chef (Bullen, Wilma, Bosse, Kent)</li><li>Klicka p\xE5d et f\xF6retaget du vill arbeta f\xF6r.</li><li>Du har nu g\xE5tt med ett f\xF6retag</li></ol><h2 id="uppsagning" tabindex="-1"><a class="header-anchor" href="#uppsagning" aria-hidden="true">#</a> Upps\xE4gning</h2><p>...</p>',24);function s(n,d){return t}var l=a(r,[["render",s],["__file","f\xF6retag.html.vue"]]);export{l as default};
